import{_ as a,p as e,q as s,a1 as n}from"./framework-5866ffd3.js";const i={},d=n(`<h1 id="lp" tabindex="-1"><a class="header-anchor" href="#lp" aria-hidden="true">#</a> lp</h1><p>打印文件或修改排队的打印任务</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>lp命令</strong> 用于打印文件，或者修改排队的打印任务。与lpr命令类似，lp命令既支持文件输入也支持标准输入。它与lpr的不同之处在于它有一个不同（稍微复杂点）的参数选项设置。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lp<span class="token punctuation">(</span>选项<span class="token punctuation">)</span><span class="token punctuation">(</span>参数<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-E：与打印服务器连接时强制使用加密；
-U：指定连接打印服务器时使用的用户名；
-d：指定接收打印任务的目标打印机；
-i：指定一个存在的打印任务号；
-m：打印完成时发送E-mail；
-n：指定打印的份数；
-t：指定打印任务的名称；
-H：指定打印任务开始的时间；
-P：指定需要打印的页码。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><p>文件：需打印的文件。</p><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>要在连接在设备dlp0上的打印机lp0上打印文件<code>/etc/motd</code>，请输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lp /etc/motd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要使用文件的一个副本打印<code>/etc/motd</code>文件的30个副本，并且要用邮件通知用户作业完成，请输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lp <span class="token parameter variable">-c</span> <span class="token parameter variable">-m</span> <span class="token parameter variable">-n30</span> <span class="token parameter variable">-dlp0:lpd0</span> /etc/motd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要使用后端标志-f和-a并带上作业标题blah打印<code>/etc/motd</code>文件，请输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lp <span class="token parameter variable">-t</span> <span class="token string">&quot;blah&quot;</span> <span class="token parameter variable">-o</span> <span class="token parameter variable">-f</span> <span class="token parameter variable">-o</span> <span class="token parameter variable">-a</span> /etc/motd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要排队MyFile文件并返回作业编号，请输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lp myfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要排队MyFile文件并禁止作业编号，请输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lp <span class="token parameter variable">-s</span> myfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>退出状态</strong></p><p>该命令返回以下退出值：</p><ul><li>0：所有输入文件成功处理。</li><li><blockquote><p>0：没有输出设备可用，或者出现一个错误。</p></blockquote></li></ul>`,24),l=[d];function r(c,t){return e(),s("div",null,l)}const o=a(i,[["render",r],["__file","lp.html.vue"]]);export{o as default};
